# Ultimate Betting Predictions Card

Here's a premium BTTS predictions card with glassmorphism design, dark theme, and emerald/gold accents:

```jsx
import React, { useState, useEffect } from 'react';
import { motion, AnimatePresence } from 'framer-motion';

const PredictionCard = () => {
  const [isHovered, setIsHovered] = useState(false);
  const [isVisible, setIsVisible] = useState(false);

  useEffect(() => {
    setIsVisible(true);
  }, []);

  const matchData = {
    team1: "Manchester City",
    team2: "Liverpool",
    league: "Premier League",
    bttsPrediction: "Oui",
    over25Prediction: "Oui",
    date: "12 Juin 2023",
    time: "20:00",
    odds: {
      btts: 1.75,
      over25: 1.90
    }
  };

  const predictionVariants = {
    hidden: { opacity: 0, y: 20 },
    visible: { 
      opacity: 1, 
      y: 0,
      transition: { duration: 0.5, ease: "easeOut" }
    }
  };

  const teamVariants = {
    hidden: { opacity: 0, scale: 0.8 },
    visible: { 
      opacity: 1, 
      scale: 1,
      transition: { duration: 0.3, delay: 0.1 }
    }
  };

  return (
    <AnimatePresence>
      {isVisible && (
        <motion.div
          className="relative w-full max-w-md mx-auto"
          variants={predictionVariants}
          initial="hidden"
          animate="visible"
          exit="hidden"
        >
          {/* Glassmorphism container */}
          <div 
            className={`relative backdrop-blur-lg rounded-2xl border border-white/10 shadow-2xl overflow-hidden transition-all duration-300 ${
              isHovered ? 'shadow-emerald-500/20' : ''
            }`}
            onMouseEnter={() => setIsHovered(true)}
            onMouseLeave={() => setIsHovered(false)}
            style={{
              background: 'linear-gradient(145deg, rgba(15, 23, 42, 0.8), rgba(30, 41, 59, 0.6))',
              boxShadow: isHovered 
                ? '0 20px 25px -5px rgba(0, 212, 170, 0.1), 0 10px 10px -5px rgba(0, 0, 0, 0.04)' 
                : '0 10px 15px -3px rgba(0, 0, 0, 0.1), 0 4px 6px -2px rgba(0, 0, 0, 0.05)'
            }}
          >
            {/* Header with league badge */}
            <div className="px-6 pt-6 pb-4">
              <div className="flex items-center justify-between">
                <div className="flex items-center space-x-2">
                  <div className="w-3 h-3 rounded-full bg-emerald-400 animate-pulse"></div>
                  <span className="text-xs font-medium text-gray-300 uppercase tracking-wider">
                    {matchData.league}
                  </span>
                </div>
                <div className="flex items-center space-x-2">
                  <span className="text-sm font-medium text-gray-300">{matchData.date}</span>
                  <span className="text-sm font-medium text-amber-400">{matchData.time}</span>
                </div>
              </div>
            </div>

            {/* Teams section */}
            <div className="px-6 pb-4">
              <div className="flex items-center justify-between">
                <motion.div 
                  className="text-center"
                  variants={teamVariants}
                >
                  <div className="w-12 h-12 rounded-full bg-gradient-to-br from-slate-700 to-slate-800 flex items-center justify-center mx-auto mb-2">
                    <span className="text-white font-bold text-sm">MC</span>
                  </div>
                  <h3 className="text-lg font-bold text-white">{matchData.team1}</h3>
                </motion.div>

                <div className="px-4">
                  <div className="text-3xl font-bold text-white mb-1">VS</div>
                  <div className="text-xs text-gray-400">En direct</div>
                </div>

                <motion.div 
                  className="text-center"
                  variants={teamVariants}
                >
                  <div className="w-12 h-12 rounded-full bg-gradient-to-br from-slate-700 to-slate-800 flex items-center justify-center mx-auto mb-2">
                    <span className="text-white font-bold text-sm">LIV</span>
                  </div>
                  <h3 className="text-lg font-bold text-white">{matchData.team2}</h3>
                </motion.div>
              </div>
            </div>

            {/* Predictions section */}
            <div className="px-6 pb-6">
              <div className="grid grid-cols-2 gap-4">
                <motion.div 
                  className={`rounded-xl p-4 transition-all duration-300 ${
                    matchData.bttsPrediction === 'Oui' 
                      ? 'bg-emerald-500/10 border border-emerald-500/30' 
                      : 'bg-rose-500/10 border border-rose-500/30'
                  }`}
                  whileHover={{ scale: 1.02 }}
                >
                  <div className="flex items-center justify-between mb-2">
                    <span className="text-xs font-medium text-gray-300 uppercase tracking-wider">
                      Les deux équipes marquent
                    </span>
                    <div className={`px-2 py-1 rounded-full text-xs font-bold ${
                      matchData.bttsPrediction === 'Oui' 
                        ? 'bg-emerald-500/20 text-emerald-400' 
                        : 'bg-rose-500/20 text-rose-400'
                    }`}>
                      {matchData.bttsPrediction}
                    </div>
                  </div>
                  <div className="flex items-baseline">
                    <span className="text-xl font-bold text-white mr-1">
                      {matchData.odds.btts}
                    </span>
                    <span className="text-xs text-gray-400">Cote</span>
                  </div>
                </motion.div>

                <motion.div 
                  className={`rounded-xl p-4 transition-all duration-300 ${
                    matchData.over25Prediction === 'Oui' 
                      ? 'bg-emerald-500/10 border border-emerald-500/30' 
                      : 'bg-rose-500/10 border border-rose-500/30'
                  }`}
                  whileHover={{ scale: 1.02 }}
                >
                  <div className="flex items-center justify-between mb-2">
                    <span className="text-xs font-medium text-gray-300 uppercase tracking-wider">
                      Plus de 2.5 buts
                    </span>
                    <div className={`px-2 py-1 rounded-full text-xs font-bold ${
                      matchData.over25Prediction === 'Oui' 
                        ? 'bg-emerald-500/20 text-emerald-400' 
                        : 'bg-rose-500/20 text-rose-400'
                    }`}>
                      {matchData.over25Prediction}
                    </div>
                  </div>
                  <div className="flex items-baseline">
                    <span className="text-xl font-bold text-white mr-1">
                      {matchData.odds.over25}
                    </span>
                    <span className="text-xs text-gray-400">Cote</span>
                  </div>
                </motion.div>
              </div>
            </div>

            {/* Action button */}
            <div className="px-6 pb-6">
              <motion.button
                className="w-full py-3 bg-gradient-to-r from-emerald-500 to-emerald-600 text-white font-bold rounded-xl shadow-lg hover:shadow-emerald-500/30 transition-all duration-300"
                whileHover={{ scale: 1.02 }}
                whileTap={{ scale: 0.98 }}
              >
                Parier Maintenant
              </motion.button>
            </div>

            {/* Decorative elements */}
            <div className="absolute top-0 right-0 w-32 h-32 bg-gradient-to-br from-emerald-500/10 to-transparent rounded-full -mr-16 -mt-16"></div>
            <div className="absolute bottom-0 left-0 w-24 h-24 bg-gradient-to-tr from-amber-500/10 to-transparent rounded-full -ml-12 -mb-12"></div>
          </div>

          {/* Floating accent elements */}
          {isHovered && (
            <>
              <motion.div
                className="absolute top-4 right-4 w-2 h-2 rounded-full bg-emerald-400"
                initial={{ scale: 0 }}
                animate={{ scale: [0, 1, 0] }}
                transition={{ duration: 1.5, repeat: Infinity }}
              />
              <motion.div
                className="absolute bottom-4 left-4 w-2 h-2 rounded-full bg-amber-400"
                initial={{ scale: 0 }}
                animate={{ scale: [0, 1, 0] }}
                transition={{ duration: 1.5, repeat: Infinity, delay: 0.5 }}
              />
            </>
          )}
        </motion.div>
      )}
    </AnimatePresence>
  );
};

export default PredictionCard;
```

## Key Features:

1. **Glassmorphism Design**: Semi-transparent background with backdrop blur and subtle borders
2. **Dark Theme**: Deep slate background with light text for contrast
3. **Color Accents**: Emerald (#00D4AA) for positive predictions and gold (#F59E0B) for highlights
4. **Animations**:
   - Framer Motion for entrance animations
   - Hover effects on the card and interactive elements
   - Pulsing indicators for live status
   - Floating accent elements that appear on hover
5. **Premium Trading Platform Feel**:
   - Clean, organized layout with clear information hierarchy
   - Team badges with initials
   - Odds display for each prediction
   - Gradient buttons and subtle shadows
   - Responsive grid for predictions
6. **Interactive Elements**:
   - Hover states on all interactive components
   - Scale animations on buttons and prediction cards
   - Tap animations for mobile devices

The card displays all requested information (teams, league, BTTS prediction, Over 2.5 prediction, date, and time) in a visually appealing, professional layout that would fit perfectly in a premium betting predictions platform.
